VALUES
  ('police-8b7f1efc-moex-00407', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '警察實務工作經常需面臨裁量決定的問題。Souryal（1998）提出警察人員執法裁量公式：E=PJ2， 下列敘述何者錯誤？', '["E代表合乎倫理的裁量決定（theEthicalDecision）", "P代表道德原則（thePrinciple）", "J代表情境的正當性（theJustificationoftheSituation）", "道德原則（P）是變數，情境正當性（J）為常數"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "cc74839149f8", "answer_pdf_sha1": "363d3fe37f37", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00408', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '關於情境犯罪預防（SituationalCrimePrevention）的敘述，下列何者錯誤？', '["情境犯罪預防源自於美國建築師 OscarNewman於1970年代所提出的「防衛空間」的概念", "根據「防衛空間」的概念，認為可以藉著特殊的建築設計降低犯罪的機會，而達到犯罪預防的 效果", "在1971年，美國犯罪學家MarcusFelson認為建築物的安全裝置、門鎖、街燈及守望相助等均 能有效減少犯罪", "1997年，RonaldClarke統整了情境犯罪預防的策略，並提出情境犯罪預防理論"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "cc74839149f8", "answer_pdf_sha1": "363d3fe37f37", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00409', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '警政方案評估研究的演進與公共政策評估有相似的發展階段，根據Kerley（2005）的主張，有關 警察政策評估的演進歷程，下列敘述何者錯誤？', '["研究途徑：從結果評估趨向過程評估", "研究設計：從實驗設計趨向非實驗設計", "研究工具：從量化方法趨向質化方法", "研究範圍：從區域性研究趨向全國性研究"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "cc74839149f8", "answer_pdf_sha1": "363d3fe37f37", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00410', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '有關我國警察之犯罪被害人保護，下列敘述何者錯誤？', '["警政主管機關應負責犯罪被害人之人身安全保護、提供關懷協助相關資訊、告知警政偵辦重要 進度、刑事偵、審程序及權益等事項", "司法警察（官）於執行職務時，發現犯罪被害人或其家屬符合法律扶助法所定申請要件時，得 告知其可依法提出申請", "警察機關應於知悉案件發生後，提供犯罪被害人或其家屬緊急救援、人身安全、關懷服務及必 要協助，並應自知悉犯罪被害人或其家屬聯絡資訊起二十四小時內，通報或轉介相關機關或分 會提供協助", "司法、警察、矯正、醫療、教育、心理及社會工作等從事犯罪被害人保護工作之相關機關（構） 或團體，應將犯罪被害人權益保障及保護服務之相關措施、法規等課程納入例行性教育訓練"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "cc74839149f8", "answer_pdf_sha1": "363d3fe37f37", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00411', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '1980年以後，社區警政及因而延伸的警政策略，已成為各國警政的趨勢。關於各國警政策略的發 展及其內涵，下列敘述何者錯誤？', '["社區導向警政（Community-orientedpolicing）主張，警察要鼓勵社區民眾分擔治安責任", "問題導向警政（Problem-orientedpolicing）係由美國警政學者Goldstein所提出", "第三造警政（Third-partypolicing）係透過法律的規範，課以第三造參與犯罪預防或控制的責任", "犯罪符號警政（Sign-of-crimepolicing）主張警察應處理民眾關切且重大的問題，以免問題惡化"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "cc74839149f8", "answer_pdf_sha1": "363d3fe37f37", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00412', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '根據Oscar Newman（1973）的研究，建築物必須要具備四個要素之一或二者以上，方能有效抑 制犯罪的發生，下列何者為非？', '["自我歸屬感（Ownership）的存在", "自然監控（NaturalSurveillance）的存在", "建築物給人良好的形象（Image）", "建築物四週有安全的環境（Milieu）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "cc74839149f8", "answer_pdf_sha1": "363d3fe37f37", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
