  ('police-8b7f1efc-moex-00415', 'police-8b7f1efc', 'police-8b7f1efc-moex-112-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '關於評估「警察機關之組織結構及能力，是否足以承擔政策方案的執行工作」之敘述，最符合下 列那個政策方案可行性分析的面向？', '["法律可行性", "行政可行性", "經濟可行性", "技術可行性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:14+00:00", "source_pdf_sha1": "cc74839149f8", "answer_pdf_sha1": "363d3fe37f37", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "501", "s": "1210", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
